SELECT DATE_FORMAT(payment_date, '%Y-%m') AS settlementMonth, SUM(payment_price) AS totalSales, SUM(payment_fee) AS totalFee, SUM(payment_price - payment_fee) AS netAmount, COUNT(*) AS txCount FROM PAYMENT WHERE trainer_id = #{trainerId} AND payment_type = 'PT' AND status = '결제완료' GROUP BY settlementMonth ORDER BY
totalSales netAmount txCount settlementMonth
${sortDir} LIMIT #{limit} OFFSET #{offset}
